ALTER TABLE "users" ADD COLUMN "platformAdmin" BOOLEAN NOT NULL DEFAULT false, ADD COLUMN "sessionVersion" INTEGER NOT NULL DEFAULT 0;
CREATE TABLE "feature_flags" ("id" TEXT NOT NULL,"key" TEXT NOT NULL,"description" TEXT NOT NULL DEFAULT '',"enabled" BOOLEAN NOT NULL DEFAULT false,"companyId" TEXT,"plan" "SubscriptionPlan","environment" TEXT,"rolloutPercent" INTEGER NOT NULL DEFAULT 100,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "feature_flags_pkey" PRIMARY KEY ("id"),CONSTRAINT "feature_flags_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "companies"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "system_error_events" ("id" TEXT NOT NULL,"companyId" TEXT,"source" TEXT NOT NULL,"severity" TEXT NOT NULL,"message" TEXT NOT NULL,"fingerprint" TEXT,"requestId" TEXT,"path" TEXT,"durationMs" INTEGER,"metadata" JSONB,"resolvedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "system_error_events_pkey" PRIMARY KEY ("id"),CONSTRAINT "system_error_events_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "companies"("id") ON DELETE SET NULL ON UPDATE CASCADE);
CREATE TABLE "system_notifications" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"userId" TEXT,"channel" TEXT NOT NULL,"title" TEXT NOT NULL,"body" TEXT NOT NULL,"status" TEXT NOT NULL DEFAULT 'Pending',"readAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "system_notifications_pkey" PRIMARY KEY ("id"),CONSTRAINT "system_notifications_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "companies"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "company_usage_daily" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"date" TIMESTAMP(3) NOT NULL,"activeUsers" INTEGER NOT NULL DEFAULT 0,"storageBytes" BIGINT NOT NULL DEFAULT 0,"apiRequests" INTEGER NOT NULL DEFAULT 0,"estimates" INTEGER NOT NULL DEFAULT 0,"jobs" INTEGER NOT NULL DEFAULT 0,"pdfs" INTEGER NOT NULL DEFAULT 0,"emails" INTEGER NOT NULL DEFAULT 0,CONSTRAINT "company_usage_daily_pkey" PRIMARY KEY ("id"),CONSTRAINT "company_usage_daily_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "companies"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "user_devices" ("id" TEXT NOT NULL,"userId" TEXT NOT NULL,"deviceHash" TEXT NOT NULL,"ipHash" TEXT,"userAgent" TEXT,"firstSeenAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"lastSeenAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"revokedAt" TIMESTAMP(3),CONSTRAINT "user_devices_pkey" PRIMARY KEY ("id"),CONSTRAINT "user_devices_userId_fkey" FOREIGN KEY ("userId") REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "admin_impersonations" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"adminUserId" TEXT NOT NULL,"reason" TEXT NOT NULL,"startedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"endedAt" TIMESTAMP(3),CONSTRAINT "admin_impersonations_pkey" PRIMARY KEY ("id"),CONSTRAINT "admin_impersonations_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "companies"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE UNIQUE INDEX "feature_flags_key_companyId_plan_environment_key" ON "feature_flags"("key","companyId","plan","environment"); CREATE INDEX "feature_flags_key_enabled_idx" ON "feature_flags"("key","enabled"); CREATE INDEX "system_error_events_createdAt_severity_idx" ON "system_error_events"("createdAt","severity"); CREATE INDEX "system_error_events_companyId_createdAt_idx" ON "system_error_events"("companyId","createdAt"); CREATE INDEX "system_notifications_companyId_userId_status_createdAt_idx" ON "system_notifications"("companyId","userId","status","createdAt"); CREATE UNIQUE INDEX "company_usage_daily_companyId_date_key" ON "company_usage_daily"("companyId","date"); CREATE INDEX "company_usage_daily_date_idx" ON "company_usage_daily"("date"); CREATE UNIQUE INDEX "user_devices_userId_deviceHash_key" ON "user_devices"("userId","deviceHash"); CREATE INDEX "user_devices_lastSeenAt_idx" ON "user_devices"("lastSeenAt"); CREATE INDEX "admin_impersonations_companyId_startedAt_idx" ON "admin_impersonations"("companyId","startedAt");
